diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
index d4a2fe5e37ef..687991251a73 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
@@ -815,7 +815,15 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
       return new ICmpInst(ICmpInst::ICMP_EQ, X, CmpC);
     }

+    // Special case: trunc (lshr/ashr X, Width-1) to i1 --> icmp slt X, 0 (extract sign bit)
+    // This case doesn't require OneUse since icmp slt is often cheaper than (and X, mask)
     Constant *C;
+    if (match(Src, m_LShr(m_Value(X), m_ImmConstant(C))) &&
+        isa<ConstantInt>(C) && cast<ConstantInt>(C)->getValue() == SrcWidth - 1)
+      return new ICmpInst(ICmpInst::ICMP_SLT, X, Zero);
+    if (match(Src, m_AShr(m_Value(X), m_ImmConstant(C))) &&
+        isa<ConstantInt>(C) && cast<ConstantInt>(C)->getValue() == SrcWidth - 1)
+      return new ICmpInst(ICmpInst::ICMP_SLT, X, Zero);
     if (match(Src, m_OneUse(m_LShr(m_Value(X), m_ImmConstant(C))))) {
       // trunc (lshr X, C) to i1 --> icmp ne (and X, C'), 0
       Constant *One = ConstantInt::get(SrcTy, APInt(SrcWidth, 1));
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 73ba0f78e805..e677fb68c317 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -4443,6 +4443,16 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+  // select (xor C, true), C, false --> false
+  // select (xor C, true), false, C --> C
+  Value *XorOp;
+  if (match(CondVal, m_c_Xor(m_Value(XorOp), m_One()))) {
+    if (XorOp == TrueVal && match(FalseVal, m_Zero()))
+      return replaceInstUsesWith(SI, ConstantInt::getFalse(SelType));
+    if (XorOp == FalseVal && match(TrueVal, m_Zero()))
+      return replaceInstUsesWith(SI, XorOp);
+  }
+
   // select Cond, !X, X -> xor Cond, X
   if (CondVal->getType() == SI.getType() && isKnownInversion(FalseVal, TrueVal))
     return BinaryOperator::CreateXor(CondVal, FalseVal);

